usage_examples.duckdb:
SELECT *
FROM 'data/normalized/regiones.parquet'
ORDER BY codigo_region;

SELECT *
FROM 'data/normalized/provincias.parquet'
WHERE codigo_region = '13';

SELECT codigo_comuna, nombre_comuna, nombre_region
FROM 'data/normalized/comunas.parquet'
LIMIT 10;

SELECT codigo_comuna, nombre_comuna, latitud_cabecera, longitud_cabecera, poblacion_estimada
FROM 'data/normalized/comunas.parquet'
ORDER BY poblacion_estimada DESC LIMIT 10;

SELECT *
FROM 'data/normalized/indicadores.parquet'
ORDER BY fecha DESC, codigo_indicador;

SELECT comuna_tributaria, count(*) AS n
FROM 'data/normalized/empresas.parquet'
GROUP BY 1 ORDER BY n DESC LIMIT 10;

SELECT nombre, cargo, codigo_comuna, codigo_region
FROM 'data/normalized/autoridades_locales.parquet'
WHERE cargo = 'alcalde';
